import { NextRequest } from 'next/server'
import { prisma } from '@/lib/prisma'
import { requireAuth, getTenantId, successResponse, errorResponse } from '@/lib/api'
import { z } from 'zod'

const ADMIN = ['IT_ADMIN', 'TENANT_ADMIN', 'SUPER_ADMIN']

const AdSchema = z.object({
  isEnabled:      z.boolean(),
  ldapUrl:        z.string().optional().nullable(),
  ldapBaseDn:     z.string().optional().nullable(),
  ldapBindDn:     z.string().optional().nullable(),
  ldapBindPass:   z.string().optional().nullable(),
  ldapUserFilter: z.string().optional().nullable(),
  groupRoleMap:   z.string().optional().nullable(),
})

export async function GET(req: NextRequest) {
  const { error, session } = await requireAuth(ADMIN)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant context', 400)
  const config = await prisma.adConfig.findUnique({ where: { tenantId } })
  if (config?.ldapBindPass) (config as any).ldapBindPass = '••••••••'
  return successResponse(config)
}

export async function PATCH(req: NextRequest) {
  const { error, session } = await requireAuth(ADMIN)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant context', 400)

  const body = await req.json()
  const parse = AdSchema.safeParse(body)
  if (!parse.success) return errorResponse(parse.error.message)

  const data: any = { ...parse.data }
  if (data.ldapBindPass === '••••••••') delete data.ldapBindPass

  const config = await prisma.adConfig.upsert({
    where: { tenantId },
    update: data,
    create: { tenantId, ...data },
  })
  return successResponse({ ...config, ldapBindPass: config.ldapBindPass ? '••••••••' : '' })
}

// POST = test LDAP connection
export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth(ADMIN)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant context', 400)

  const config = await prisma.adConfig.findUnique({ where: { tenantId } })
  if (!config?.ldapUrl) return errorResponse('LDAP URL not configured')

  try {
    const { Client } = await import('ldapts')
    const client = new Client({ url: config.ldapUrl, tlsOptions: { rejectUnauthorized: false }, timeout: 5000 })
    await client.bind(config.ldapBindDn ?? '', config.ldapBindPass ?? '')
    await client.unbind()
    return successResponse({ ok: true, message: 'LDAP connection successful' })
  } catch (err: any) {
    return errorResponse('LDAP test failed: ' + err.message, 500)
  }
}
